  var stars=[[0.04,0.08],[0.12,0.18],[0.23,0.05],[0.41,0.10],[0.52,0.28],[0.60,0.08],[0.69,0.19],[0.79,0.07],[0.87,0.25],[0.08,0.38],[0.38,0.52],[0.56,0.48],[0.74,0.55],[0.15,0.70],[0.45,0.60],[0.07,0.85]];
