  ctx.fillStyle=pGrad;ctx.beginPath();ctx.arc(px,py,pr,0,Math.PI*2);ctx.fill();
  ctx.strokeStyle='rgba(160,140,255,0.5)';ctx.lineWidth=8;ctx.beginPath();ctx.ellipse(px,py,pr*1.8,pr*0.35,-0.25,0,Math.PI*2);ctx.stroke();
