function isUsingDefaultStageStyle(style) {
  return textStyleMatches(getResolvedTextStyle(style), getBaseTextStyle());
}

function getAnimatedTeachingTextColor(segmentColor, rowText, rowIndex, segmentIndex, characterIndex = 0) {
  // Ã¢â€â‚¬Ã¢â€â‚¬ Key-Value mode: color chars before ':' as key, after as value Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
  if (state.displayStyle.kvMode && window._kvState && window._kvState.colonGlobal >= 0) {
    const currentChar = state.drawnCharCount || 0;
    if (currentChar <= window._kvState.colonGlobal) {
      return window._kvState.keyColor;
    }
    return window._kvState.valueColor;
  }

  const isOutcomes = normalizePresentationTemplate(state.presentationTemplate) === PRESENTATION_TEMPLATE_OUTCOMES;

  // Preserve explicit custom colours (glossary red, user highlights) UNLESS we're on
  // template 2 and the colour is one of the two defaults (#ffffff or #000000) Ã¢â‚¬â€
  // both need to be overridden to white on the new dark cosmic background.
  const isDefaultColor = !segmentColor || segmentColor === "#ffffff" || segmentColor === "#000000";
  if (!isDefaultColor) {
    return segmentColor; // real custom color Ã¢â‚¬â€ keep it
  }

  // Template 2: dark cosmic background Ã¢â‚¬â€ always force white text.
  if (isOutcomes) {
    return "#ffffff";
  }

  return getBaseTextStyle().color || "#ffffff";
}

function drawAnimatedTeachingSegment(segment, x, y, rowText, rowIndex, segmentIndex, fontSize) {
  const text = segment.text || "";
  let cursorX = x;
  // Glossary segments carry textStartIndex (position in state.text) so alpha fading
  // uses the exact sync position instead of drawnCharCount, giving smooth per-char
  // fade-in in both templates without column-offset misalignment.
  const hasTextIndex = segment.textStartIndex !== undefined && Number.isFinite(segment.textStartIndex);
  const isAnimating = state.speaking && state.exactCharCountFloat !== undefined;
  // Butter fade: each character glides in over 2 char-widths of the speech cursor
  // — silky smooth reveal that flows with the voice, no abrupt pop-in.
  const FADE_RANGE = 2.0;

  const graphemes = getGraphemes(text);
  let charOffset = 0;
  for (let index = 0; index < graphemes.length; index += 1) {
    const character = graphemes[index];
    const characterWidth = ctx.measureText(character).width;
    const globalCharIndex = (state.drawnCharCount || 0);

    ctx.fillStyle = getAnimatedTeachingTextColor(segment.style.color, rowText, rowIndex, segmentIndex, index);

    if (isAnimating) {
      const charRef = hasTextIndex ? (segment.textStartIndex + charOffset) : globalCharIndex;
      const rawAlpha = clamp((state.exactCharCountFloat - charRef) / FADE_RANGE, 0, 1);
      // Smoothstep S-curve: slow start → fast mid → slow finish — butter smooth, no pop
      const easedAlpha = rawAlpha * rawAlpha * (3 - 2 * rawAlpha);
      ctx.globalAlpha = easedAlpha;

      const glowRef = hasTextIndex ? (segment.textStartIndex + charOffset) : globalCharIndex;
      const distFromCursor = Math.abs(glowRef - state.exactCharCountFloat);
      // Wide glow trail: chars within 2 char-widths of the cursor shimmer with a
      // flowing blue-white typewriter-light wash as the voice moves through them.
      if (distFromCursor < 2.0 && easedAlpha > 0.01 && easedAlpha < 0.99) {
        const glowStrength = clamp(1 - distFromCursor / 2.0, 0, 1);
        const glowOpacity = Math.round(glowStrength * 72);
        ctx.shadowColor = `rgba(13, 126, 169, ${(glowOpacity / 100).toFixed(2)})`;
        ctx.shadowBlur = 8 + glowStrength * 14;
        ctx.shadowOffsetY = 0;
      } else {
        ctx.shadowColor = "rgba(8, 30, 39, 0.20)";
        ctx.shadowBlur = 5;
        ctx.shadowOffsetY = 1;
      }
    } else {
      ctx.shadowColor = "rgba(8, 30, 39, 0.24)";
      ctx.shadowBlur = 6;
      ctx.shadowOffsetY = 1;
    }

    ctx.fillText(character, cursorX, y);

    ctx.globalAlpha = 1.0;
    state.drawnCharCount = (state.drawnCharCount || 0) + character.length;
    // letter spacing: em units → pixels relative to current font size
    const _lsPx = (state.displayStyle?.canvasLetterSpacing ?? 0) * fontSize;
    // KV gap: after the separator character (':' or '='), inject a visual gap
    const _isSep = state.displayStyle?.kvMode && window._kvState &&
      (character === ":" || character === "=");
    const _kvGap = _isSep ? Math.round(fontSize * 0.35) : 0;
    cursorX += characterWidth + _lsPx + _kvGap;
    charOffset += character.length;
  }

  ctx.shadowColor = "transparent";
  ctx.shadowBlur = 0;
  ctx.shadowOffsetY = 0;
  return cursorX - x;
}

function drawSceneVfx() {
  if (normalizePresentationTemplate(state.presentationTemplate) === PRESENTATION_TEMPLATE_OUTCOMES) {
    return;
  }

  const palette = Array.isArray(state.scene.palette) && state.scene.palette.length >= 3
    ? state.scene.palette
    : ["#0e84ad", "#4eb6de", "#ffb548"];
  const vfx = state.scene.vfx || "sparkles";
  const rawTime = getPlaybackElapsedSec();
  const exportMotionScale = state.exportingVideo ? 0.45 : 1;
  const time = rawTime * exportMotionScale;
  const boardTop = 118;
  const boardHeight = canvas.height - boardTop;

  ctx.save();
  ctx.beginPath();
  ctx.rect(0, boardTop, canvas.width, boardHeight);
  ctx.clip();

  if (vfx === "bubbles") {
    const bubbleCount = state.exportingVideo ? 12 : 16;
    for (let index = 0; index < bubbleCount; index += 1) {
      const radius = 16 + (index % 4) * 10;
      const x = ((index * 93) + (time * 28) + 70) % (canvas.width + 120) - 60;
      const y = boardTop + (((index * 71) - (time * 24)) % (boardHeight + 160)) + 30;
      ctx.fillStyle = `rgba(255, 255, 255, ${0.06 + (index % 3) * 0.02})`;
      ctx.beginPath();
      ctx.arc(x, y, radius, 0, Math.PI * 2);
      ctx.fill();
    }
  } else if (vfx === "waves") {
    for (let waveIndex = 0; waveIndex < 4; waveIndex += 1) {
      ctx.beginPath();
      ctx.lineWidth = 10 + (waveIndex * 2);
      ctx.strokeStyle = `rgba(255,255,255,${0.07 - waveIndex * 0.01})`;
      for (let x = -40; x <= canvas.width + 40; x += 12) {
        const waveAmplitude = state.exportingVideo ? 10 : 22;
        const y = boardTop + 120 + (waveIndex * 80) + Math.sin((x / 110) + time + waveIndex) * waveAmplitude;
        if (x === -40) {
          ctx.moveTo(x, y);
        } else {
          ctx.lineTo(x, y);
        }
      }
      ctx.stroke();
    }
  } else if (vfx === "rays") {
    for (let rayIndex = 0; rayIndex < 6; rayIndex += 1) {
      ctx.save();
      ctx.translate(canvas.width * 0.5, boardTop + 220);
      ctx.rotate((-0.8 + rayIndex * 0.28) + Math.sin(time * 0.22) * (state.exportingVideo ? 0.012 : 0.03));
      const gradient = ctx.createLinearGradient(0, -20, 0, 340);
      gradient.addColorStop(0, "rgba(255,255,255,0.18)");
      gradient.addColorStop(1, "rgba(255,255,255,0)");
      ctx.fillStyle = gradient;
      ctx.fillRect(-30, -20, 60, 340);
      ctx.restore();
    }
  } else if (vfx === "confetti") {
    const colors = [...palette, "#ffffff"];
    const confettiCount = state.exportingVideo ? 16 : 24;
    for (let index = 0; index < confettiCount; index += 1) {
      const x = ((index * 61) + time * 42) % (canvas.width + 60) - 30;
      const y = boardTop + ((index * 47) % (boardHeight - 40)) + 20;
      const size = 8 + (index % 3) * 3;
      ctx.save();
      ctx.translate(x, y);
      ctx.rotate((index * 0.7) + time * 0.3);
      ctx.fillStyle = colors[index % colors.length];
      ctx.globalAlpha = 0.22;
      ctx.fillRect(-size * 0.5, -size * 0.5, size, size * 0.62);
      ctx.restore();
    }
  } else if (vfx === "grid") {
    ctx.strokeStyle = "rgba(255,255,255,0.08)";
    ctx.lineWidth = 1;
    for (let x = 24; x <= canvas.width; x += 46) {
      ctx.beginPath();
      ctx.moveTo(x, boardTop);
      ctx.lineTo(x, canvas.height);
      ctx.stroke();
    }
    for (let y = boardTop + 12; y <= canvas.height; y += 42) {
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(canvas.width, y);
      ctx.stroke();
    }
  } else {
    const sparkleCount = state.exportingVideo ? 14 : 18;
    for (let index = 0; index < sparkleCount; index += 1) {
      const baseX = 56 + ((index * 173) % Math.max(120, canvas.width - 112));
      const baseY = boardTop + 28 + ((index * 131) % Math.max(120, boardHeight - 56));
      const x = state.exportingVideo ? baseX : ((index * 79) + time * 24) % canvas.width;
      const y = state.exportingVideo
        ? baseY + Math.sin((time * 0.9) + index) * 4
        : boardTop + ((index * 59) % boardHeight);
      const radius = 3 + (index % 4);
      const alpha = state.exportingVideo
        ? 0.08 + ((Math.sin((time * 1.2) + index) + 1) * 0.04)
        : (0.16 - (index % 3) * 0.02);
      ctx.fillStyle = `rgba(255,255,255,${alpha})`;
      ctx.beginPath();
      ctx.arc(x, y, radius, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillRect(x - 1, y - 10, 2, 20);
      ctx.fillRect(x - 10, y - 1, 20, 2);
    }
  }

  ctx.restore();
}

