// Ã¢â€â‚¬Ã¢â€â‚¬ AI Captions: word-level SRT generation Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
function generateWordLevelSrt(text, durationMs, playbackRate = 1) {
  if (!text || !durationMs) return "";
  const words = text.replace(/\s+/g, " ").trim().split(" ").filter(w => w.length > 0);
  if (!words.length) return "";

  const totalTimeMs = Math.max(1, Math.round(durationMs / Math.max(0.1, playbackRate)));
  const entries = [];
  let charIndex = 0;
  const totalChars = text.replace(/\s+/g, " ").trim().length;

  for (let i = 0; i < words.length; i++) {
    const word = words[i];
    // Calculate start/end time based on character position (linear mapping)
    const startFraction = charIndex / totalChars;
    const endFraction = Math.min(1, (charIndex + word.length) / totalChars);
    const startMs = Math.round(startFraction * totalTimeMs);
    const endMs = Math.round(endFraction * totalTimeMs);

    // Group words into 4-5 word caption chunks for readability
    const chunkSize = 5;
    const chunkIndex = Math.floor(i / chunkSize);
    if (i % chunkSize === 0) {
      // Start a new caption entry
      const chunkWords = words.slice(i, Math.min(i + chunkSize, words.length));
      const chunkText = chunkWords.join(" ");
      const lastWordInChunk = Math.min(i + chunkSize - 1, words.length - 1);
      let lastCharIdx = 0;
      for (let j = 0; j <= lastWordInChunk; j++) {
        lastCharIdx += words[j].length + 1;
      }
      const chunkEndFraction = Math.min(1, lastCharIdx / totalChars);
      const chunkEndMs = Math.round(chunkEndFraction * totalTimeMs);

      entries.push({
        index: chunkIndex + 1,
        startMs: startMs,
        endMs: Math.max(startMs + 200, chunkEndMs),
        text: chunkText
      });
    }

    charIndex += word.length + 1; // +1 for space
  }

  // Format as SRT
  const formatTime = (ms) => {
    const hours = Math.floor(ms / 3600000);
    const minutes = Math.floor((ms % 3600000) / 60000);
    const seconds = Math.floor((ms % 60000) / 1000);
    const millis = ms % 1000;
    return `${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")},${String(millis).padStart(3, "0")}`;
  };

  return entries.map(e =>
    `${e.index}\n${formatTime(e.startMs)} --> ${formatTime(e.endMs)}\n${e.text}\n`
  ).join("\n");
}

function downloadSrtFile(srtContent, fileName = "captions.srt") {
  const blob = new Blob([srtContent], { type: "text/srt;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = fileName;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

// ── AI Caption module: Text to Speech + Speech to Text buttons ───────────────
(function wireAiCapVoiceButtons() {
  let _audio = null, _playing = false;
  const status = () => document.getElementById("aiCapVoiceStatus");

  // ── TTS: reads lesson text via Chatterbox narration server ──────────────────
  document.addEventListener("click", async (e) => {
    const btn = e.target.closest("#aiCapTtsBtn");
    if (!btn) return;
    if (_playing && _audio) {
      _audio.pause(); _audio = null; _playing = false;
      btn.style.background = "linear-gradient(135deg,#1a73e8,#0d47a1)";
      btn.innerHTML = `<svg width="17" height="17" viewBox="0 0 24 24" fill="currentColor"><path d="M3 9v6h4l5 5V4L7 9H3zm13.5 3A4.5 4.5 0 0 0 14 7.97v8.05c1.48-.73 2.5-2.25 2.5-4.02zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77s-2.99-7.86-7-8.77z"/></svg> 🔊 Text to Speech`;
      if (status()) status().textContent = "";
      return;
    }
    const text = (getEffectiveLessonText() || "").trim();
    if (!text) { if (status()) status().textContent = "⚠ No lesson text to read."; return; }
    btn.disabled = true;
    btn.style.background = "linear-gradient(135deg,#f57c00,#e65100)";
    btn.innerHTML = `<svg width="17" height="17" viewBox="0 0 24 24" fill="currentColor"><path d="M12 4V1L8 5l4 4V6c3.31 0 6 2.69 6 6s-2.69 6-6 6-6-2.69-6-6H4c0 4.42 3.58 8 8 8s8-3.58 8-8-3.58-8-8-8z"/></svg> ⏳ Generating...`;
    if (status()) status().textContent = "⏳ Generating voice...";
    try {
      const voice = window.state?.preferredNarrationVoice || "sc3";
      const resp = await fetch("http://127.0.0.1:5111/api/narrate", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text, generationOptions: { voice } })
      });
      if (!resp.ok) throw new Error("Server " + resp.status);
      _audio = new Audio(URL.createObjectURL(await resp.blob()));
      _playing = true; btn.disabled = false;
      btn.style.background = "linear-gradient(135deg,#c62828,#b71c1c)";
      btn.innerHTML = `<svg width="17" height="17" viewBox="0 0 24 24" fill="currentColor"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"/></svg> ⏹ Stop`;
      if (status()) status().textContent = "🔊 Playing — click to stop";
      _audio.onended = () => {
        _playing = false; _audio = null;
        btn.style.background = "linear-gradient(135deg,#1a73e8,#0d47a1)";
        btn.innerHTML = `<svg width="17" height="17" viewBox="0 0 24 24" fill="currentColor"><path d="M3 9v6h4l5 5V4L7 9H3zm13.5 3A4.5 4.5 0 0 0 14 7.97v8.05c1.48-.73 2.5-2.25 2.5-4.02zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77s-2.99-7.86-7-8.77z"/></svg> 🔊 Text to Speech`;
        if (status()) status().textContent = "✔ Done.";
      };
      _audio.play();
    } catch(err) {
      btn.disabled = false;
      btn.style.background = "linear-gradient(135deg,#1a73e8,#0d47a1)";
      btn.innerHTML = `<svg width="17" height="17" viewBox="0 0 24 24" fill="currentColor"><path d="M3 9v6h4l5 5V4L7 9H3zm13.5 3A4.5 4.5 0 0 0 14 7.97v8.05c1.48-.73 2.5-2.25 2.5-4.02zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77s-2.99-7.86-7-8.77z"/></svg> 🔊 Text to Speech`;
      if (status()) status().textContent = "❌ " + err.message;
    }
  });

  // ── 🎥 Transcribe Video → Captions (STT button = video audio transcription) ─
  document.addEventListener("click", (e) => {
    const btn = e.target.closest("#aiCapSttBtn");
    if (!btn) return;

    const videoInput  = document.getElementById("captionVideoInput");
    const sourceVideo = document.getElementById("captionSourceVideo");
    const actionBtn   = document.getElementById("captionActionBtn");
    const statusText  = document.getElementById("captionStatusText");
    const progressBlock = document.getElementById("captionProgress");

    // Check video is loaded
    const hasFile = videoInput && videoInput.files && videoInput.files.length > 0;
    const hasVideoSrc = sourceVideo && sourceVideo.src && !sourceVideo.src.endsWith(window.location.href);

    if (!hasFile && !hasVideoSrc) {
      if (status()) status().textContent = "⚠️ Upload a video in the Source Video field first!";
      // Flash the upload input to draw attention
      const uploadInput = document.getElementById("captionVideoInput");
      if (uploadInput) {
        uploadInput.style.outline = "3px solid #f44336";
        setTimeout(() => { uploadInput.style.outline = ""; }, 2000);
      }
      return;
    }

    // If actionBtn is disabled but a video IS loaded — re-enable it
    if (actionBtn && actionBtn.disabled && hasFile) {
      actionBtn.disabled = false;
      actionBtn.textContent = "Generate Captions";
    }

    if (!actionBtn || actionBtn.disabled) {
      if (status()) status().textContent = "⚠️ Caption engine busy — wait a moment and try again.";
      return;
    }

    // Clear old status + show progress
    if (status()) status().textContent = "🎥 Extracting video audio → Whisper transcription...";
    if (statusText) statusText.innerHTML = "⏳ Starting transcription from video audio...";
    if (progressBlock) progressBlock.classList.remove("hidden");

    btn.disabled = true;
    btn.style.background = "linear-gradient(135deg,#f57c00,#e65100)";
    btn.innerHTML = `<svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3zm-1-9c0-.55.45-1 1-1s1 .45 1 1v6c0 .55-.45 1-1 1s-1-.45-1-1V5zm6 6c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z"/></svg> ⏳ Transcribing video...`;

    // Watch for actionBtn to be re-enabled (means transcription done or failed)
    const observer = new MutationObserver(() => {
      if (!actionBtn.disabled) {
        observer.disconnect();
        btn.disabled = false;
        btn.style.background = "linear-gradient(135deg,#e53935,#b71c1c)";
        btn.innerHTML = `<svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3zm-1-9c0-.55.45-1 1-1s1 .45 1 1v6c0 .55-.45 1-1 1s-1-.45-1-1V5zm6 6c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z"/></svg> 🎥 Transcribe Video → Captions`;
        if (status()) status().textContent = "✅ Done! Timed captions generated from video audio.";
      }
    });
    observer.observe(actionBtn, { attributes: true, attributeFilter: ["disabled"] });

    // Trigger the real pipeline: extractAudio → Whisper → timed segments
    actionBtn.click();
  });
})();

// Use event delegation so the handler works even if React hasn't rendered StagePanel yet
// ── Caption panel: Text to Speech button ────────────────────────────────────
(function wireCaptionVoiceButtons() {
  let _ttsAudio = null, _ttsPlaying = false;
  let _sttRec = null, _sttActive = false;
  const statusEl = () => document.getElementById("captionVoiceBtnStatus");

  // TTS — reads lesson text via Chatterbox narration server
  document.addEventListener("click", async (e) => {
    const btn = e.target.closest("#captionTtsBtn");
    if (!btn) return;
    if (_ttsPlaying && _ttsAudio) {
      _ttsAudio.pause(); _ttsAudio = null; _ttsPlaying = false;
      btn.style.background = "linear-gradient(135deg,#1a73e8,#0d47a1)";
      btn.querySelector("span:last-child") && (btn.lastChild.textContent = " Text to Speech");
      if (statusEl()) statusEl().textContent = "Stopped.";
      return;
    }
    const text = (getEffectiveLessonText() || "").trim();
    if (!text) { if (statusEl()) statusEl().textContent = "⚠ No lesson text to read."; return; }
    btn.disabled = true;
    btn.style.background = "linear-gradient(135deg,#f57c00,#e65100)";
    if (statusEl()) statusEl().textContent = "⏳ Generating voice...";
    try {
      const voice = window.state?.preferredNarrationVoice || "sc3";
      const resp = await fetch("http://127.0.0.1:5111/api/narrate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text, generationOptions: { voice } })
      });
      if (!resp.ok) throw new Error(`Server ${resp.status}`);
      const blob = await resp.blob();
      _ttsAudio = new Audio(URL.createObjectURL(blob));
      _ttsPlaying = true;
      btn.disabled = false;
      btn.style.background = "linear-gradient(135deg,#c62828,#b71c1c)";
      if (statusEl()) statusEl().textContent = "🔊 Playing... click to stop.";
      _ttsAudio.onended = () => {
        _ttsPlaying = false; _ttsAudio = null;
        btn.style.background = "linear-gradient(135deg,#1a73e8,#0d47a1)";
        if (statusEl()) statusEl().textContent = "✔ Done.";
      };
      _ttsAudio.play();
    } catch(err) {
      btn.disabled = false;
      btn.style.background = "linear-gradient(135deg,#1a73e8,#0d47a1)";
      if (statusEl()) statusEl().textContent = "❌ " + err.message;
    }
  });

  // STT — listens to mic, appends to lesson input in Indian English
  document.addEventListener("click", (e) => {
    const btn = e.target.closest("#captionSttBtn");
    if (!btn) return;
    const SpeechRec = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRec) { if (statusEl()) statusEl().textContent = "❌ Use Chrome/Edge for mic input."; return; }
    if (_sttActive && _sttRec) { _sttRec.stop(); return; }
    _sttRec = new SpeechRec();
    _sttRec.lang = "en-IN";
    _sttRec.continuous = true;
    _sttRec.interimResults = true;
    _sttRec.maxAlternatives = 1;
    _sttActive = true;
    btn.style.background = "linear-gradient(135deg,#c62828,#b71c1c)";
    if (statusEl()) statusEl().textContent = "🎙 Listening... click to stop.";
    _sttRec.onresult = (ev) => {
      let final = "";
      for (let i = ev.resultIndex; i < ev.results.length; i++) {
        if (ev.results[i].isFinal) final += ev.results[i][0].transcript + " ";
      }
      if (final && lessonInput) {
        lessonInput.value = mergeSpeechText(lessonInput.value, final.trim());
        scheduleLessonInputChange(0);
        if (statusEl()) statusEl().textContent = "🎙 Got: " + final.trim().slice(0, 60);
      }
    };
    _sttRec.onerror = (ev) => { if (statusEl()) statusEl().textContent = "⚠ " + ev.error; };
    _sttRec.onend = () => {
      _sttActive = false; _sttRec = null;
      btn.style.background = "linear-gradient(135deg,#2e7d32,#1b5e20)";
      if (statusEl()) statusEl().textContent = "✔ Recording stopped.";
    };
    _sttRec.start();
  });
})();

document.addEventListener("click", async (e) => {
  const captionExportBtn = e.target.closest("#stageCaptionExportBtn");
  if (!captionExportBtn) return;
  e.preventDefault();
  e.stopPropagation();
  {
    // Ã¢â€â‚¬Ã¢â€â‚¬ MODE 1: If a stage video is loaded, transcribe its audio for burned-in captions Ã¢â€â‚¬Ã¢â€â‚¬
    if (state.stageVideo.element && state.stageVideo.element.src) {
      try {
        setStatus("Preparing AI transcription...");
        captionOverlay.transcribing = true;

        // Check transcription server
        const serverReady = await ensureTranscribeServer();
        if (!serverReady) {
          throw new Error("The local transcription server is not running. Start it to enable AI captions.");
        }

        // Ã¢â€â‚¬Ã¢â€â‚¬ Crash-free IPC path Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
        // Old code: fetch(url) Ã¢â€ â€™ arrayBuffer Ã¢â€ â€™ WAV blob Ã¢â€ â€™ base64 Ã¢â€ â€™ OOM crash
        // New code: pass file path to main process via IPC.
        // Main process: FFmpeg extracts 16kHz mono WAV (~9 MB for 5 min video)
        //   Ã¢â€ â€™ sends to transcription server Ã¢â€ â€™ returns {text, segments}.
        // Renderer memory usage: ~0 bytes of video data loaded here.
        if (!window.electronAPI || !window.electronAPI.transcribeVideo || !state.stageVideo.blob) {
          throw new Error("Transcription requires the Electron app. Please use the desktop app.");
        }
        setStatus("Extracting audio and transcribing with AI (this may take a moment)...");
        const videoPath = window.electronAPI.getPathForFile(state.stageVideo.blob);
        if (!videoPath) throw new Error("Could not get video file path. Please re-upload the video.");

        const result = await window.electronAPI.transcribeVideo({ videoPath });
        if (!result.ok) throw new Error(result.error || "Transcription failed.");

        const payload = result; // { ok, text, segments, words }
        const transcript = (payload.text || "").trim();
        if (!transcript) {
          throw new Error("No speech was recognized from the video audio.");
        }

        // Parse word-level timestamps if available, otherwise create linear segments
        const segments = [];
        if (payload.segments && Array.isArray(payload.segments)) {
          // Use server-provided word-level segments
          for (const seg of payload.segments) {
            segments.push({
              startMs: Math.round((seg.start || 0) * 1000),
              endMs: Math.round((seg.end || 0) * 1000),
              text: (seg.text || "").trim()
            });
          }
        } else if (payload.words && Array.isArray(payload.words)) {
          // Group words into 5-word chunks
          const words = payload.words;
          for (let i = 0; i < words.length; i += 5) {
            const chunk = words.slice(i, Math.min(i + 5, words.length));
            segments.push({
              startMs: Math.round((chunk[0].start || 0) * 1000),
              endMs: Math.round((chunk[chunk.length - 1].end || 0) * 1000),
              text: chunk.map(w => w.word || w.text || "").join(" ").trim()
            });
          }
        } else {
          // Fallback: use linear timing from the transcript
          const videoDurationMs = (state.stageVideo.element.duration || 60) * 1000;
          const srtText = generateWordLevelSrt(transcript, videoDurationMs, 1);
          // Parse the SRT back into segments
          const srtLines = srtText.split("\n\n").filter(Boolean);
          for (const block of srtLines) {
            const lines = block.split("\n");
            if (lines.length >= 3) {
              const timeParts = lines[1].split(" --> ");
              if (timeParts.length === 2) {
                segments.push({
                  startMs: parseSrtTime(timeParts[0]),
                  endMs: parseSrtTime(timeParts[1]),
                  text: lines.slice(2).join(" ").trim()
                });
              }
            }
          }
        }

        captionOverlay.segments = segments
          .map(seg => ({
            startMs: Math.max(0, Math.round(Number(seg.startMs) || 0)),
            endMs: Math.max(0, Math.round(Number(seg.endMs) || 0)),
            text: String(seg.text || "").replace(/\s+/g, " ").trim()
          }))
          .filter(seg => seg.text && seg.endMs > seg.startMs)
          .sort((a, b) => a.startMs - b.startMs);
        captionOverlay.enabled = true;
        captionOverlay.currentText = getCaptionTextForTimeMs(0) || (captionOverlay.segments[0]?.text || transcript.substring(0, 60));

        setStatus(`Ã¢Å“â€¦ AI transcription complete! ${segments.length} caption segments created. Drag the caption bar to position it, then export.`);
        markSceneDirty();

        // Start lightweight caption sync loop
        startCaptionUpdateLoop();

        // Also download the SRT file
        const srt = segments.map((seg, i) => {
          const formatMs = (ms) => {
            const h = Math.floor(ms / 3600000);
            const m = Math.floor((ms % 3600000) / 60000);
            const s = Math.floor((ms % 60000) / 1000);
            const ml = ms % 1000;
            return `${String(h).padStart(2,"0")}:${String(m).padStart(2,"0")}:${String(s).padStart(2,"0")},${String(ml).padStart(3,"0")}`;
          };
          return `${i+1}\n${formatMs(seg.startMs)} --> ${formatMs(seg.endMs)}\n${seg.text}\n`;
        }).join("\n");
        if (srt) {
          const baseName = getDefaultExportFileName().replace(/\.\w+$/, "");
          downloadSrtFile(srt, `${baseName}.srt`);
        }
        // Inject the video's original audio as narration so the export uses it
        // instead of generating TTS. Set the transcript as lesson text.
        const exportText = transcript || getEffectiveLessonText() || "Captioned video";
        state.text = exportText;
        state.displayedText = "";
        await ensureVideoExportServer();
        const wavBlob = await extractMediaAudioToWavBlob(state.stageVideo.blob, state.stageVideo.fileName || "stage-video.mp4");
        await setNarrationFromBlob(
          wavBlob,
          state.stageVideo.fileName || "stage-video-audio.wav",
          "Extracted from stage video for caption export",
          exportText,
          EXPORT_NARRATION_VOICE,
          { silent: true }
        );
        setStatus("Audio injected. Starting video export with burned-in captions...");

        // Now trigger export with burned-in captions
        void beginExportFromUi(exportVideo, {
          suggestedName: getDefaultExportFileName()
        });

      } catch (error) {
        console.error(error);
        captionOverlay.transcribing = false;
        setStatus(`Caption generation failed: ${error.message}`);
      } finally {
        captionOverlay.transcribing = false;
      }
      return;
    }

    // Ã¢â€â‚¬Ã¢â€â‚¬ MODE 2: Lesson text only Ã¢â€ â€™ generate SRT from narration timing Ã¢â€â‚¬Ã¢â€â‚¬
    const text = getEffectiveLessonText();
    if (!text || !text.trim()) {
      setStatus("Upload a stage video or enter lesson text first to generate AI captions.");
      return;
    }

    try {
      setStatus("Generating AI captions from lesson narration...");

      const narrationBlob = await ensureAnjaliNarrationReadyForExport({
        textSource: text,
        timeoutMs: getLongNarrationRequestTimeoutMs(text),
        skipPreparedExportSchedule: true
      });
      const durationMs = await measureNarrationBlobDurationMs(narrationBlob);
      const playbackRate = getLessonPlaybackRate();

      // Generate word-level segments for burned-in captions.
      // IMPORTANT: use the NARRATION TEXT (what TTS actually speaks), not the raw
      // lesson text – buildNarrationText() expands shortcuts, injects teacher pauses,
      // and verbalizes math. Using its output for character-count timing ensures each
      // segment's duration matches the audio stream precisely.
      const narText   = buildNarrationText(text);
      const srcText   = narText || text;
      const words = srcText.replace(/\s+/g, " ").trim().split(" ").filter(w => w.length > 0);
      const totalTimeMs = Math.max(1, Math.round(durationMs / Math.max(0.1, playbackRate)));
      const totalChars = srcText.replace(/\s+/g, " ").trim().length;
      const segments = [];
      let charIdx = 0;
      for (let i = 0; i < words.length; i += 5) {
        const chunk = words.slice(i, Math.min(i + 5, words.length));
        const startFrac = charIdx / totalChars;
        let endCharIdx = charIdx;
        for (const w of chunk) { endCharIdx += w.length + 1; }
        const endFrac = Math.min(1, endCharIdx / totalChars);
        segments.push({
          startMs: Math.round(startFrac * totalTimeMs),
          endMs: Math.max(Math.round(startFrac * totalTimeMs) + 200, Math.round(endFrac * totalTimeMs)),
          text: chunk.join(" ")
        });
        for (const w of chunk) { charIdx += w.length + 1; }
      }

      captionOverlay.segments = segments;
      captionOverlay.enabled = true;
      captionOverlay.currentText = segments.length > 0 ? segments[0].text : "";

      // Download SRT
      const srt = generateWordLevelSrt(text, durationMs, playbackRate);
      if (srt) {
        const baseName = getDefaultExportFileName().replace(/\.\w+$/, "");
        downloadSrtFile(srt, `${baseName}.srt`);
        setStatus("Captions (.srt) downloaded! Burned-in captions enabled. Starting export...");
      }

      // Start lightweight caption sync loop
      startCaptionUpdateLoop();

      markSceneDirty();

      void beginExportFromUi(exportVideo, {
        suggestedName: getDefaultExportFileName()
      });
    } catch (error) {
      console.error(error);
      setStatus(`Caption generation failed: ${error.message}. Trying video export without captions...`);
      void beginExportFromUi(exportVideo, {
        suggestedName: getDefaultExportFileName()
      });
    }
  }
});
// Helper: parse SRT timestamp "HH:MM:SS,mmm" to milliseconds
function parseSrtTime(str) {
  const parts = str.trim().replace(",", ".").split(":");
  if (parts.length !== 3) return 0;
  return Math.round(
    parseFloat(parts[0]) * 3600000 +
    parseFloat(parts[1]) * 60000 +
    parseFloat(parts[2]) * 1000
  );
}

