// Ã¢â€â‚¬Ã¢â€â‚¬ Input Style Controls (Line Spacing / Font Size / Letter Spacing) Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// Sliders live above the lessonInput textarea. Changes apply instantly and are
// saved to localStorage so your preferred settings survive every reload.
(function initInputStyleControls() {
  const LS_KEY   = 'pp-input-style-v1';
  const DEFAULTS = { lineHeight: 2.1, fontSize: 0.98, letterSpacing: 0.01 };

  const textarea = document.getElementById('lessonInput');
  const sliderLH = document.getElementById('inputLineHeight');
  const valLH    = document.getElementById('inputLineHeightVal');
  const sliderFS = document.getElementById('inputFontSize');
  const valFS    = document.getElementById('inputFontSizeVal');
  const sliderLS = document.getElementById('inputLetterSpacing');
  const valLS    = document.getElementById('inputLetterSpacingVal');
  const resetBtn = document.getElementById('inputStyleResetBtn');

  if (!textarea || !sliderLH || !sliderFS || !sliderLS) return;

  function applyStyle(lh, fs, ls) {
    textarea.style.lineHeight    = String(lh);
    textarea.style.fontSize      = `${fs}rem`;
    textarea.style.letterSpacing = `${ls}em`;
  }

  function syncDisplays(lh, fs, ls) {
    valLH.textContent = String(lh);
    valFS.textContent = `${fs}rem`;
    valLS.textContent = `${Number(ls).toFixed(3)}em`;
  }

  function save(lh, fs, ls) {
    try { localStorage.setItem(LS_KEY, JSON.stringify({ lineHeight: lh, fontSize: fs, letterSpacing: ls })); } catch (_) {}
  }

  function load() {
    try { return JSON.parse(localStorage.getItem(LS_KEY) || 'null') || DEFAULTS; }
    catch (_) { return DEFAULTS; }
  }

  // Boot: restore saved values
  const init = load();
  sliderLH.value = init.lineHeight;
  sliderFS.value = init.fontSize;
  sliderLS.value = init.letterSpacing;
  applyStyle(init.lineHeight, init.fontSize, init.letterSpacing);
  syncDisplays(init.lineHeight, init.fontSize, init.letterSpacing);
  // Seed canvas state with saved spacing
  if (typeof updateDisplayStyle === "function") {
    updateDisplayStyle({
      canvasLineSpacing: parseFloat(init.lineHeight) / DEFAULTS.lineHeight,
      canvasLetterSpacing: parseFloat(init.letterSpacing)
    });
  }

  // Live updates
  sliderLH.addEventListener('input', () => {
    const v = parseFloat(sliderLH.value);
    textarea.style.lineHeight = String(v);
    valLH.textContent = String(v);
    save(v, parseFloat(sliderFS.value), parseFloat(sliderLS.value));
    // Canvas: update line spacing and force redraw regardless of active panel
    const lineMul = v / DEFAULTS.lineHeight;
    updateDisplayStyle({ canvasLineSpacing: lineMul });
    invalidateDrawSceneLayoutCache && invalidateDrawSceneLayoutCache();
    markSceneDirty && markSceneDirty();
    drawScene(state.mouthOpen);
  });

  sliderFS.addEventListener('input', () => {
    const v = parseFloat(sliderFS.value);
    textarea.style.fontSize = `${v}rem`;
    valFS.textContent = `${v}rem`;
    save(parseFloat(sliderLH.value), v, parseFloat(sliderLS.value));
  });

  sliderLS.addEventListener('input', () => {
    const v = parseFloat(sliderLS.value);
    textarea.style.letterSpacing = `${v}em`;
    valLS.textContent = `${v.toFixed(3)}em`;
    save(parseFloat(sliderLH.value), parseFloat(sliderFS.value), v);
    // Canvas: letter spacing Ã¢â‚¬â€ bust cache so new spacing applies to row widths
    updateDisplayStyle({ canvasLetterSpacing: v });
    invalidateDrawSceneLayoutCache && invalidateDrawSceneLayoutCache();
    markSceneDirty && markSceneDirty();
    drawScene(state.mouthOpen);
  });

  // Reset to defaults
  resetBtn?.addEventListener('click', () => {
    const { lineHeight, fontSize, letterSpacing } = DEFAULTS;
    sliderLH.value = lineHeight;
    sliderFS.value = fontSize;
    sliderLS.value = letterSpacing;
    applyStyle(lineHeight, fontSize, letterSpacing);
    syncDisplays(lineHeight, fontSize, letterSpacing);
    save(lineHeight, fontSize, letterSpacing);
    // Reset canvas spacing too
    updateDisplayStyle({ canvasLineSpacing: 1.0, canvasLetterSpacing: 0.0 });
    invalidateDrawSceneLayoutCache && invalidateDrawSceneLayoutCache();
    markSceneDirty && markSceneDirty();
    drawScene(state.mouthOpen);
  });
}());


// ── ONE-TIME template card click delegation ─────────────────────────────────
// Uses event delegation so clicks always work with zero listener accumulation.
(function initTemplateCardDelegation() {
  // NO guard - runs exactly once per script load (script is injected once per page load)

  // ── 1. stageTemplateSelect dropdown via document change delegation ──────
  // change event bubbles from <select> to document. Works regardless of when
  // React renders the element or whether stagePanel is hidden.
  document.addEventListener('change', function(e) {
    if (!e.target) return;
    if (e.target.id === 'stageTemplateSelect') {
      var val = e.target.value;
      if (!val) return;
      // Force state update and redraw unconditionally
      try {
        if (typeof setPresentationTemplate === 'function') {
          setPresentationTemplate(val);
        } else if (typeof window.setPresentationTemplate === 'function') {
          window.setPresentationTemplate(val);
        }
        // Mark dirty so the animation loop redraws on next tick
        // (Do NOT call drawScene(0) here - it resets _lastDrawnMouthOpen to 0
        //  which breaks the mouth-sync check during active narration.)
        try {
          if (typeof markSceneDirty === 'function') markSceneDirty();
        } catch (_e2) {}
      } catch (_e3) {
        console.error('stageTemplateSelect change error:', _e3);
      }
    }
  });
  document.addEventListener('click', function(e) {
    // Check if user clicked a Select button
    var btn = e.target.closest && e.target.closest('.tpl3d-select-btn');
    if (btn) {
      e.stopPropagation();
      var tplId = btn.getAttribute('data-tpl');
      if (tplId && typeof setPresentationTemplate === 'function') {
        setPresentationTemplate(tplId);
      }
      return;
    }
    // Check if user clicked anywhere on the card itself
    var card = e.target.closest && e.target.closest('.tpl3d-card');
    if (card) {
      var tplId2 = card.getAttribute('data-template');
      if (tplId2 && typeof setPresentationTemplate === 'function') {
        setPresentationTemplate(tplId2);
      }
    }
  }, false);
}());


// ── TOP-LEVEL stageTemplateSelect change listener (safety net) ──────────────
// This fires even if the initTemplateCardDelegation IIFE fails for any reason.
document.addEventListener('change', function _topLevelTplChange(e) {
  if (e && e.target && e.target.id === 'stageTemplateSelect') {
    var _v = e.target.value;
    if (!_v) return;
    try {
      if (typeof setPresentationTemplate === 'function') setPresentationTemplate(_v);
    } catch (_ex) {}
    try {
      if (typeof markSceneDirty === 'function') markSceneDirty();
    } catch (_ex2) {}
  }
});

// == Chatterbox Voice Loading Banner ==
(function initChatterboxBanner() {
  const HEALTH_URL = 'http://127.0.0.1:8426/health';
  const POLL_MS    = 3000;
  const DOTS       = ['\u280b','\u2819','\u2839','\u2838','\u283c','\u2834','\u2826','\u2827','\u2807','\u280f'];
  const style = document.createElement('style');
  style.textContent = `
    #cb-voice-banner{position:fixed;top:0;left:0;right:0;z-index:99999;background:linear-gradient(90deg,#0f172a,#1e293b);color:#e2e8f0;font-family:'Segoe UI',system-ui,sans-serif;font-size:13px;box-shadow:0 2px 16px rgba(0,0,0,.5);transition:transform .4s ease,opacity .4s ease;}
    #cb-voice-banner.cb-hidden{transform:translateY(-100%);opacity:0;pointer-events:none;}
    #cb-voice-inner{display:flex;align-items:center;gap:10px;padding:8px 16px;}
    #cb-voice-spinner{font-size:16px;flex-shrink:0;color:#60a5fa;}
    #cb-voice-text{flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;}
    #cb-voice-text strong{color:#93c5fd;}
    #cb-voice-sub{color:#94a3b8;font-size:11px;margin-left:4px;}
    #cb-voice-bar-wrap{width:120px;height:4px;background:#334155;border-radius:2px;flex-shrink:0;overflow:hidden;}
    #cb-voice-bar{height:100%;width:15%;background:linear-gradient(90deg,#3b82f6,#8b5cf6);border-radius:2px;transition:width .8s ease;}
    #cb-voice-ok{display:none;color:#4ade80;font-size:16px;font-weight:700;}
    #cb-voice-banner.cb-done{background:linear-gradient(90deg,#052e16,#14532d);}
    #cb-voice-banner.cb-done #cb-voice-spinner,#cb-voice-banner.cb-done #cb-voice-bar-wrap{display:none;}
    #cb-voice-banner.cb-done #cb-voice-ok{display:inline;}
    #cb-voice-banner.cb-done strong{color:#86efac;}
  `;
  document.head.appendChild(style);
  const banner = document.createElement('div');
  banner.id = 'cb-voice-banner';
  banner.innerHTML = '<div id="cb-voice-inner"><span id="cb-voice-spinner">' + DOTS[0] + '</span><span id="cb-voice-ok">&#10003; Ready</span><span id="cb-voice-text"><strong>Voice Presentator</strong><span id="cb-voice-sub"> Loading EVS C5 lesson voice from sc3.mp4Ã¢â‚¬Â¦</span></span><div id="cb-voice-bar-wrap"><div id="cb-voice-bar"></div></div></div>';
  document.body.prepend(banner);
  const spinner = document.getElementById('cb-voice-spinner');
  const sub     = document.getElementById('cb-voice-sub');
  const bar     = document.getElementById('cb-voice-bar');
  let dotIdx = 0, pollTimer = null, start = Date.now();
  const dotTimer = setInterval(function(){ spinner.textContent = DOTS[dotIdx = (dotIdx+1)%DOTS.length]; }, 100);
  function markReady() {
    clearInterval(dotTimer); clearTimeout(pollTimer);
    bar.style.width = '100%';
    banner.classList.add('cb-done');
    sub.textContent = '';
    setTimeout(function(){ banner.classList.add('cb-hidden'); }, 4000);
  }
  function poll() {
    fetch(HEALTH_URL, {cache:'no-store'}).then(function(r){ return r.json(); }).then(function(d) {
      var elapsed = Math.round((Date.now()-start)/1000);
      bar.style.width = Math.min(88, 15 + elapsed*0.9) + '%';
      if (d.chatterboxReady) { markReady(); return; }
      if (d.chatterboxError && !d.chatterboxLoading) {
        sub.textContent = ' sc3 voice clone failed. Select Edge TTS manually if you want to use it.';
        bar.style.background = 'linear-gradient(90deg,#f59e0b,#ef4444)';
        setTimeout(function(){ banner.classList.add('cb-hidden'); }, 6000);
        return;
      }
      sub.textContent = ' Loading sc3 voice model... ' + elapsed + 's';
      pollTimer = setTimeout(poll, POLL_MS);
    }).catch(function() {
      sub.textContent = ' Waiting for voice server on port 8426Ã¢â‚¬Â¦';
      pollTimer = setTimeout(poll, POLL_MS);
    });
  }
  setTimeout(poll, 1800);
}());

